 {"id":"bd-yx9r.10.3","title":"Implement gRPC codec, service, client/server, reflection, health, and web parity","description":"Upstream gRPC spans codecs, protobuf glue, client/server/service surfaces, interceptors, reflection, health, streaming, and gRPC-web. ANSI C currently has no comparable module family.","design":"Port gRPC as a real protocol stack over the service/transport/HTTP foundations, with protobuf/reflection/health behavior and explicit integration tests.","acceptance_criteria":"A. Public gRPC modules exist across core client/server/codec/interceptor/health/reflection/web families.\\nB. Tests cover unary/streaming flows, health/reflection, interceptors, and failure handling.\\nC. Logged e2e packs show gRPC server/client success and failure cases with retained artifacts.","notes":"Depends on H1, E2, and G1.","status":"open","priority":2,"issue_type":"task","created_at":"2026-03-13T20:38:43.569296679Z","created_by":"ubuntu","updated_at":"2026-03-13T22:29:53.784735326Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["crate-parity","grpc"],"dependencies":[{"issue_id":"bd-yx9r.10.3","depends_on_id":"bd-yx9r.1","type":"blocks","created_at":"2026-03-13T22:27:26.013655100Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-yx9r.10.3","depends_on_id":"bd-yx9r.10","type":"parent-child","created_at":"2026-03-13T20:38:43.569296679Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-yx9r.10.3","depends_on_id":"bd-yx9r.10.1","type":"blocks","created_at":"2026-03-13T20:39:51.694657923Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-yx9r.10.3","depends_on_id":"bd-yx9r.10.2","type":"blocks","created_at":"2026-03-13T22:27:45.950426139Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-yx9r.10.3","depends_on_id":"bd-yx9r.2","type":"blocks","created_at":"2026-03-13T22:27:27.018406370Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-yx9r.10.3","depends_on_id":"bd-yx9r.3","type":"blocks","created_at":"2026-03-13T22:27:28.082555930Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-yx9r.10.3","depends_on_id":"bd-yx9r.7.2","type":"blocks","created_at":"2026-03-13T20:39:53.083558489Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-yx9r.10.3","depends_on_id":"bd-yx9r.9.1","type":"blocks","created_at":"2026-03-13T20:39:54.438115617Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-yx9r.10.3","depends_on_id":"bd-yx9r.9.2","type":"blocks","created_at":"2026-03-13T22:29:53.783984295Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-yx9r.11","title":"Data, messaging, and distributed-systems parity","description":"The upstream crate also exposes database, messaging, and distributed runtime families that remain absent in ANSI C. These are not kernel details; they are concrete functional gaps visible in the exported module tree.","design":"This epic should explicitly track those gaps rather than leaving them hidden behind generic deferred-surface language.","acceptance_criteria":"A. Database, messaging, and distributed module families have explicit implementation beads with verification requirements.\\nB. Dependencies on network/service/trace/runtime layers are encoded in the graph.\\nC. Final crate-level parity cannot be declared without either implementing these or explicitly re-scoping the project.","notes":"Primary upstream references: src/database/*, src/messaging/*, and src/distributed/*.","status":"open","priority":2,"issue_type":"epic","created_at":"2026-03-13T20:38:45.102560069Z","created_by":"ubuntu","updated_at":"2026-03-13T20:43:24.311086121Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["crate-parity","database","distributed","messaging"],"dependencies":[{"issue_id":"bd-yx9r.11","depends_on_id":"bd-yx9r","type":"parent-child","created_at":"2026-03-13T20:38:45.102560069Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-yx9r.11","depends_on_id":"bd-yx9r.1","type":"blocks","created_at":"2026-03-13T20:39:17.847157734Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-yx9r.11","depends_on_id":"bd-yx9r.2","type":"blocks","created_at":"2026-03-13T20:39:18.940736694Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-yx9r.11","depends_on_id":"bd-yx9r.3","type":"blocks","created_at":"2026-03-13T20:39:20.044429956Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
