+    if (hdrs == NULL || name == NULL) return 0u;
+    removed = 0u;
+    write = 0u;
+    for (i = 0u; i < hdrs->count; i++) {
+        if (http_strcasecmp(hdrs->entries[i].name, name) == 0) {
+            removed++;
+        } else {
+            if (write != i) hdrs->entries[write] = hdrs->entries[i];
+            write++;
+        }
+    }
+    hdrs->count = write;
+    return removed;
+}
