+    asx_ancillary anc_inbox;
+    uint32_t generation;
+    uint32_t peer_slot;
+    uint32_t peer_generation;
+    int alive;
+    int linked;
+} unix_stream_slot;
+
+static unix_stream_slot g_unix_streams[ASX_MAX_UNIX_STREAMS];
