+    if (out == NULL) return ASX_E_INVALID_ARGUMENT;
+    s = unix_listener_lookup(listener);
+    if (s == NULL) return ASX_E_INVALID_ARGUMENT;
+    if (s->accept_count == 0u) return ASX_E_PENDING;
