+    s = unix_listener_lookup(listener);
+    if (s == NULL) return ASX_E_INVALID_ARGUMENT;
+
+    for (i = 0u; i < s->accept_count; i++) {
+        uint32_t idx = (s->accept_head + i) % ASX_UNIX_ACCEPT_QUEUE_DEPTH;
