+TEST(quic_datagram_disabled) {
+    asx_quic_conn conn;
+    asx_quic_config cfg;
+    uint8_t payload[] = "x";
+    asx_buf src;
+    asx_buf_mut dst;
+    uint32_t read_n;
+
+    asx_quic_reset();
+    asx_quic_config_init(&cfg);
+    cfg.enable_datagrams = 0u;
+    ASSERT_EQ(asx_quic_connect(&conn, &cfg), ASX_OK);
